import{_ as e,o as l,c as a,a3 as r}from"./chunks/framework.BTFg6ESq.js";const b=JSON.parse('{"title":"项目概览","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/project-overview.md","filePath":"user-guide/project-overview.md","lastUpdated":1778221347000}'),o={name:"user-guide/project-overview.md"};function n(i,t,s,d,h,g){return l(),a("div",null,[...t[0]||(t[0]=[r(`<h1 id="项目概览" tabindex="-1">项目概览 <a class="header-anchor" href="#项目概览" aria-label="Permalink to &quot;项目概览&quot;">​</a></h1><p>欢迎来到 <strong>AIO Hub</strong> —— 你的专属 AI 创作与开发工作站。这份概览将带你快速了解这个工具能为你做什么，以及它适合什么样的你。</p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><h3 id="aio-hub-是什么" tabindex="-1">AIO Hub 是什么？ <a class="header-anchor" href="#aio-hub-是什么" aria-label="Permalink to &quot;AIO Hub 是什么？&quot;">​</a></h3><p>AIO Hub 是一个<strong>跨平台的桌面应用程序</strong>，它把 LLM（大语言模型）对话、30+ 专业工具和强大的插件系统整合到一个统一的工作台中。简单来说，它是一个你可以<strong>自由组装</strong>的工具箱。</p><h3 id="它解决什么问题" tabindex="-1">它解决什么问题？ <a class="header-anchor" href="#它解决什么问题" aria-label="Permalink to &quot;它解决什么问题？&quot;">​</a></h3><ul><li><strong>告别碎片化</strong>：AI 对话、代码工具、文件处理、正则匹配、OCR 识别……这些本来需要开五六个窗口的事情，现在一个窗口搞定。</li><li><strong>告别黑盒 Prompt</strong>：想看清楚你发给 AI 的每个 Token 到底长什么样？AIO Hub 提供全链路透明化，让你完全掌控 Prompt 的每个细节。</li><li><strong>告别死板的布局</strong>：不习惯固定的左右分栏？把聊天窗口拖出来变成独立悬浮窗，想放哪放哪。</li></ul><h3 id="适合谁用" tabindex="-1">适合谁用？ <a class="header-anchor" href="#适合谁用" aria-label="Permalink to &quot;适合谁用？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>如果你是……</th><th>你会喜欢它的……</th></tr></thead><tbody><tr><td><strong>AI 爱好者 / 角色扮演玩家</strong></td><td>强大的 LLM 对话系统、深度上下文控制、SillyTavern 世界书兼容、非线性对话树</td></tr><tr><td><strong>开发者</strong></td><td>文本差异对比、正则批量处理、Git 仓库分析、代码格式化、LLM 请求检查器</td></tr><tr><td><strong>创作者 / 写作者</strong></td><td>智能 OCR、音视频转写、富文本渲染、Markdown 实时预览、FFmpeg 媒体处理</td></tr><tr><td><strong>效率工具控</strong></td><td>自由窗口管理、插件系统、主题定制、动态壁纸、30+ 工具一站整合</td></tr></tbody></table><hr><h2 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h2><h3 id="💬-llm-智能对话大厅" tabindex="-1">💬 LLM 智能对话大厅 <a class="header-anchor" href="#💬-llm-智能对话大厅" aria-label="Permalink to &quot;💬 LLM 智能对话大厅&quot;">​</a></h3><p>不止是聊天。AIO Hub 的对话工作区支持<strong>非线性对话图谱</strong>（对话历史以树状结构展示，你可以随时在分支间切换）、<strong>上下文压缩</strong>（长对话自动智能摘要，不浪费 Token）、<strong>60+ 动态宏</strong>（插入时间/系统信息/角色变量等），以及<strong>全链路 Prompt 可视化</strong>——发送前的原始 Prompt 长什么样，一清二楚。</p><blockquote><p>如果你玩过 SillyTavern，AIO Hub 深度兼容其格式，包括世界书、角色卡、快捷动作和正则脚本。</p></blockquote><h3 id="🧰-30-专业工具集" tabindex="-1">🧰 30+ 专业工具集 <a class="header-anchor" href="#🧰-30-专业工具集" aria-label="Permalink to &quot;🧰 30+ 专业工具集&quot;">​</a></h3><p>从 API 测试、Git 分析、正则应用到视频转写、颜色提取、JSON 格式化——一应俱全。后面有详细分类。</p><h3 id="🪟-自由窗口管理" tabindex="-1">🪟 自由窗口管理 <a class="header-anchor" href="#🪟-自由窗口管理" aria-label="Permalink to &quot;🪟 自由窗口管理&quot;">​</a></h3><p>受够了固定的布局？随便拖。聊天区域、工具栏、输入框——<strong>任何组件都可以拖拽成独立窗口</strong>，贴边自动吸附，重启后还记得位置。</p><h3 id="🧩-插件系统-三种类型" tabindex="-1">🧩 插件系统（三种类型） <a class="header-anchor" href="#🧩-插件系统-三种类型" aria-label="Permalink to &quot;🧩 插件系统（三种类型）&quot;">​</a></h3><ul><li><strong>JS 插件</strong>：写一段前端脚本，动态注册功能，即写即用。</li><li><strong>Native 插件</strong>：Rust 编写的高性能后端插件。</li><li><strong>Sidecar 插件</strong>：用 Python、Go 等任何语言编写独立进程，系统统一管理。</li></ul><h3 id="🎨-极致视觉定制" tabindex="-1">🎨 极致视觉定制 <a class="header-anchor" href="#🎨-极致视觉定制" aria-label="Permalink to &quot;🎨 极致视觉定制&quot;">​</a></h3><ul><li>原生 Windows Mica / macOS Vibrancy 毛玻璃特效</li><li>动态视频/图片轮播壁纸，自适应取色</li><li>内置 CSS 编辑器，想改哪改哪（搞个赛博朋克主题？安排）</li><li>明/暗主题一键切换</li></ul><h3 id="🌍-跨平台支持" tabindex="-1">🌍 跨平台支持 <a class="header-anchor" href="#🌍-跨平台支持" aria-label="Permalink to &quot;🌍 跨平台支持&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">平台</th><th style="text-align:left;">安装格式</th></tr></thead><tbody><tr><td style="text-align:left;">Windows</td><td style="text-align:left;"><code>.exe</code> 安装包</td></tr><tr><td style="text-align:left;">macOS</td><td style="text-align:left;"><code>.dmg</code>（支持 Apple Silicon 和 Intel）</td></tr><tr><td style="text-align:left;">Linux</td><td style="text-align:left;"><code>.AppImage</code> / <code>.flatpak</code></td></tr></tbody></table><h3 id="📱-移动端-进行中" tabindex="-1">📱 移动端（进行中） <a class="header-anchor" href="#📱-移动端-进行中" aria-label="Permalink to &quot;📱 移动端（进行中）&quot;">​</a></h3><p>Android / iOS 版本正在开发中，与桌面端共享核心逻辑，触摸屏交互深度重构。</p><hr><h2 id="架构一览" tabindex="-1">架构一览 <a class="header-anchor" href="#架构一览" aria-label="Permalink to &quot;架构一览&quot;">​</a></h2><blockquote><p>这一节是<strong>面向你</strong>的通俗版解释，不是技术文档。</p></blockquote><p>AIO Hub 由三部分组成：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────┐     ┌──────────────┐     ┌──────────────┐</span></span>
<span class="line"><span>│  你看到的界面  │────▶│ 背后的核心逻辑  │────▶│  系统底层能力  │</span></span>
<span class="line"><span>│  (Vue 3 前端)  │     │  (TypeScript)  │     │  (Rust 后端)  │</span></span>
<span class="line"><span>└──────────────┘     └──────────────┘     └──────────────┘</span></span></code></pre></div><ol><li><strong>你看到的界面</strong> — 基于 Vue 3，所有按钮、输入框、聊天气泡、设置面板都在这里。</li><li><strong>背后的核心逻辑</strong> — TypeScript 编写的业务逻辑，负责处理 LLM 请求、工具之间的通信、状态管理等。</li><li><strong>系统底层能力</strong> — Rust 编写的原生能力，负责高性能计算（如正则批量处理、Git 分析）、文件系统操作、系统 API 调用（如 OCR）等。这部分你看不到，但它是&quot;快&quot;的秘诀。</li></ol><p>这三层通过 Tauri 桌面框架粘合在一起，最终打包成一个可安装的桌面应用。</p><blockquote><p>对于开发者：如果你对插件开发或自定义工具感兴趣，参考 <code>docs/guide/</code> 下的开发指南。</p></blockquote><hr><h2 id="工具体系" tabindex="-1">工具体系 <a class="header-anchor" href="#工具体系" aria-label="Permalink to &quot;工具体系&quot;">​</a></h2><p>AIO Hub 的所有工具按功能分为以下几个大类。你可以在<strong>主页的工具中心</strong>通过卡片快速启动它们，或者在已开启的<strong>顶部/侧边标签页</strong>间切换。你也可以在&quot;设置 -&gt; 工具管理&quot;中自由开关各个工具的显示状态。</p><h3 id="💬-ai-对话与上下文" tabindex="-1">💬 AI 对话与上下文 <a class="header-anchor" href="#💬-ai-对话与上下文" aria-label="Permalink to &quot;💬 AI 对话与上下文&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">工具</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>LLM 智能对话</strong></td><td style="text-align:left;">全功能 AI 聊天工作区，支持模型自由切换、对话树、上下文压缩、世界书、宏系统</td></tr><tr><td style="text-align:left;"><strong>智能体编辑器</strong></td><td style="text-align:left;">智能体人设、能力插件、模型参数、资产附件一站式管理</td></tr><tr><td style="text-align:left;"><strong>对话分支管理</strong></td><td style="text-align:left;">用树状图谱查看对话历史，支持拖拽拼接分支</td></tr><tr><td style="text-align:left;"><strong>上下文分析器</strong></td><td style="text-align:left;">查看最终发给 LLM 的原始 Prompt 和 Token 分布</td></tr><tr><td style="text-align:left;"><strong>ST 世界书编辑器</strong></td><td style="text-align:left;">独立编辑器，用于构建和维护大型设定集</td></tr></tbody></table><h3 id="🔧-开发者工具" tabindex="-1">🔧 开发者工具 <a class="header-anchor" href="#🔧-开发者工具" aria-label="Permalink to &quot;🔧 开发者工具&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">工具</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>API 测试器</strong></td><td style="text-align:left;">HTTP API 调试工具，支持 SSE 流式响应</td></tr><tr><td style="text-align:left;"><strong>JSON 格式化</strong></td><td style="text-align:left;">JSON/YAML 格式校验与格式化，可控制展开层级</td></tr><tr><td style="text-align:left;"><strong>文本差异对比</strong></td><td style="text-align:left;">两个文件对比，高亮差异，支持导出补丁</td></tr><tr><td style="text-align:left;"><strong>正则表达式应用器</strong></td><td style="text-align:left;">双引擎（前端预览 + 后端处理），支持正则流水线</td></tr><tr><td style="text-align:left;"><strong>代码格式化</strong></td><td style="text-align:left;">基于 Prettier 的多语言代码格式化</td></tr><tr><td style="text-align:left;"><strong>Git 仓库分析器</strong></td><td style="text-align:left;">提交记录、贡献者热力图、提交频率分析，大型仓库秒开</td></tr><tr><td style="text-align:left;"><strong>Token 计算器</strong></td><td style="text-align:left;">多厂商模型 Token 精确统计，含图片 Token 分析</td></tr><tr><td style="text-align:left;"><strong>LLM 请求检查器</strong></td><td style="text-align:left;">本地代理服务器，拦截分析发往 LLM 的 API 请求</td></tr><tr><td style="text-align:left;"><strong>服务注册表浏览器</strong></td><td style="text-align:left;">查看所有已注册的服务和元数据</td></tr><tr><td style="text-align:left;"><strong>工具调用核心</strong></td><td style="text-align:left;">为 LLM 提供工具调用闭环（感知 → 生成 → 执行 → 回注）</td></tr></tbody></table><h3 id="🎬-多媒体处理" tabindex="-1">🎬 多媒体处理 <a class="header-anchor" href="#🎬-多媒体处理" aria-label="Permalink to &quot;🎬 多媒体处理&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">工具</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>媒体生成器</strong></td><td style="text-align:left;">图像/音频/视频生成任务管理器，支持分支管理和任务队列</td></tr><tr><td style="text-align:left;"><strong>音视频转写</strong></td><td style="text-align:left;">多模型驱动的转写引擎，语音转文字、视频描述、PDF 分批解析</td></tr><tr><td style="text-align:left;"><strong>FFmpeg 助手</strong></td><td style="text-align:left;">视频压缩、格式转换、批量处理，Rust 后端高性能驱动</td></tr><tr><td style="text-align:left;"><strong>媒体信息读取</strong></td><td style="text-align:left;">提取 A1111/ComfyUI 等绘图元数据</td></tr><tr><td style="text-align:left;"><strong>弹幕播放器</strong></td><td style="text-align:left;">桌面弹幕展示工具</td></tr></tbody></table><h3 id="🔍-文本与内容处理" tabindex="-1">🔍 文本与内容处理 <a class="header-anchor" href="#🔍-文本与内容处理" aria-label="Permalink to &quot;🔍 文本与内容处理&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">工具</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>富文本渲染</strong></td><td style="text-align:left;">LLM 流式输出专用渲染引擎，支持 Markdown/HTML/代码高亮/图表/公式</td></tr><tr><td style="text-align:left;"><strong>智能 OCR</strong></td><td style="text-align:left;">多引擎图片文字识别（VLM + 系统原生 + 浏览器引擎），长图智能切片</td></tr><tr><td style="text-align:left;"><strong>内容去重</strong></td><td style="text-align:left;">清理重复内容</td></tr><tr><td style="text-align:left;"><strong>数据筛选</strong></td><td style="text-align:left;">JSON/YAML 列表数据条件筛选</td></tr><tr><td style="text-align:left;"><strong>目录树生成</strong></td><td style="text-align:left;">快速生成项目目录树结构</td></tr><tr><td style="text-align:left;"><strong>文本差异对比</strong></td><td style="text-align:left;">见开发者工具分类</td></tr></tbody></table><h3 id="📦-系统与资产管理" tabindex="-1">📦 系统与资产管理 <a class="header-anchor" href="#📦-系统与资产管理" aria-label="Permalink to &quot;📦 系统与资产管理&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">工具</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>资产管理器</strong></td><td style="text-align:left;">应用级资源中心，集中管理所有工具产生的文件（自动去重）</td></tr><tr><td style="text-align:left;"><strong>目录清理</strong></td><td style="text-align:left;">灵活的文件清理工具，安全模式防止误删</td></tr><tr><td style="text-align:left;"><strong>符号链接搬迁</strong></td><td style="text-align:left;">文件&quot;搬家&quot;工具，支持硬链接和符号链接</td></tr><tr><td style="text-align:left;"><strong>颜色提取器</strong></td><td style="text-align:left;">图片颜色分析 + 屏幕取色</td></tr></tbody></table><h3 id="🔌-集成与扩展" tabindex="-1">🔌 集成与扩展 <a class="header-anchor" href="#🔌-集成与扩展" aria-label="Permalink to &quot;🔌 集成与扩展&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">工具</th><th style="text-align:left;">功能</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>VCP 连接器</strong></td><td style="text-align:left;">连接到 VCP 协议后端，实时监控 RAG 检索、思考链等</td></tr><tr><td style="text-align:left;"><strong>画布</strong></td><td style="text-align:left;">自由画布，可用于绘图、笔记或流程图草图</td></tr><tr><td style="text-align:left;"><strong>组件测试器</strong></td><td style="text-align:left;">UI 组件交互测试沙盒</td></tr></tbody></table><hr><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to &quot;使用场景&quot;">​</a></h2><h3 id="场景一-ai-角色扮演与小说创作" tabindex="-1">场景一：AI 角色扮演与小说创作 <a class="header-anchor" href="#场景一-ai-角色扮演与小说创作" aria-label="Permalink to &quot;场景一：AI 角色扮演与小说创作&quot;">​</a></h3><blockquote><p>你想和 AI 角色进行沉浸式对话，同时管理庞大的人物设定。</p></blockquote><ol><li>先配置一个 LLM 服务（比如 OpenAI 或 DeepSeek）。</li><li>在&quot;智能体编辑器&quot;中创建一个角色，写好性格设定。</li><li>在&quot;ST 世界书编辑器&quot;中创建世界书，为重要关键词绑定背景故事。</li><li>开始对话。当谈到某个地点或人物时，世界书会自动注入设定。</li><li>使用对话分支管理查看对话的树状历史，随时回退到旧分支重来。</li><li>最后导出 PNG 角色卡分享给朋友。</li></ol><h3 id="场景二-日常开发辅助" tabindex="-1">场景二：日常开发辅助 <a class="header-anchor" href="#场景二-日常开发辅助" aria-label="Permalink to &quot;场景二：日常开发辅助&quot;">​</a></h3><blockquote><p>你正在开发一个项目，需要频繁地查日志、比代码、转格式。</p></blockquote><ol><li>把 AIO Hub 放在副屏，随时 AI 对话解决技术问题。</li><li>需要比对两个配置文件？拖拽进去，差异一目了然。</li><li>批量处理日志中的正则匹配？用&quot;正则应用器&quot;建一条流水线。</li><li>想了解项目的 Git 历史？交给&quot;Git 分析器&quot;秒出可视化结果。</li><li>媒体文件太大需要压缩？FFmpeg 助手一键处理。</li></ol><h3 id="场景三-资料整理与内容处理" tabindex="-1">场景三：资料整理与内容处理 <a class="header-anchor" href="#场景三-资料整理与内容处理" aria-label="Permalink to &quot;场景三：资料整理与内容处理&quot;">​</a></h3><blockquote><p>你有一堆图片、PDF、录音需要整理。</p></blockquote><ol><li>&quot;智能 OCR&quot;扫描图片中的文字，多引擎识别，准确率高。</li><li>&quot;音视频转写&quot;把会议录音转成文字稿。</li><li>&quot;内容去重&quot;清理重复段落。</li><li>&quot;数据筛选&quot;从大量 JSON 中提取你需要的内容。</li><li>把整理好的资料丢到&quot;资产管理器&quot;中统一管理。</li></ol><h3 id="场景四-多窗口高效工作流" tabindex="-1">场景四：多窗口高效工作流 <a class="header-anchor" href="#场景四-多窗口高效工作流" aria-label="Permalink to &quot;场景四：多窗口高效工作流&quot;">​</a></h3><blockquote><p>你需要同时盯着 AI 回答、查 API 文档、看日志。</p></blockquote><ol><li>把主聊天窗口的&quot;对话区域&quot;拖拽成独立悬浮窗，放到屏幕左侧。</li><li>打开&quot;API 测试器&quot;，也拖拽出来放到屏幕右侧。</li><li>主窗口切到&quot;LLM 请求检查器&quot;监控中间流量（如开启了本地代理）。</li><li>三个窗口随时可见，无需切换 Tab。</li></ol><h3 id="场景五-自定义插件扩展" tabindex="-1">场景五：自定义插件扩展 <a class="header-anchor" href="#场景五-自定义插件扩展" aria-label="Permalink to &quot;场景五：自定义插件扩展&quot;">​</a></h3><blockquote><p>你需要一个内置应用不支持的功能。</p></blockquote><ol><li>打开文档，学习 JS 插件开发（只需要一点前端经验）。</li><li>编写一个简单的 JS 文件，通过 <code>activate</code> 钩子注册你的自定义功能。</li><li>插件系统中开启它，即刻生效。</li><li>如果是复杂功能，用 Rust 写 Native 插件，或者用 Python 写 Sidecar 插件。</li></ol><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q1-aio-hub-需要联网吗" tabindex="-1">Q1：AIO Hub 需要联网吗？ <a class="header-anchor" href="#q1-aio-hub-需要联网吗" aria-label="Permalink to &quot;Q1：AIO Hub 需要联网吗？&quot;">​</a></h3><p><strong>部分功能可以离线使用。</strong> 系统提供的本地能力（正则处理、代码格式化、OCR 本地引擎、文件操作等）完全离线可用。但 LLM 对话需要联网访问 API 服务。</p><h3 id="q2-我的-api-key-安全吗" tabindex="-1">Q2：我的 API Key 安全吗？ <a class="header-anchor" href="#q2-我的-api-key-安全吗" aria-label="Permalink to &quot;Q2：我的 API Key 安全吗？&quot;">​</a></h3><p><strong>安全的。</strong> 所有 API Key 和配置数据都存储在本地，不会上传到任何服务器。你可以随时在设置中查看和管理 Key。</p><h3 id="q3-aio-hub-和-sillytavern-什么关系" tabindex="-1">Q3：AIO Hub 和 SillyTavern 什么关系？ <a class="header-anchor" href="#q3-aio-hub-和-sillytavern-什么关系" aria-label="Permalink to &quot;Q3：AIO Hub 和 SillyTavern 什么关系？&quot;">​</a></h3><p>AIO Hub <strong>不是</strong> SillyTavern 的替代品，两者定位不同。但 AIO Hub 深度兼容 SillyTavern 的格式生态，包括世界书（<code>.json</code>）、角色卡（PNG V2/V3）、快捷动作、正则脚本等。如果你是从 SillyTavern 转过来了，大部分素材可以直接导入。</p><h3 id="q4-能在手机上用吗" tabindex="-1">Q4：能在手机上用吗？ <a class="header-anchor" href="#q4-能在手机上用吗" aria-label="Permalink to &quot;Q4：能在手机上用吗？&quot;">​</a></h3><p><strong>桌面版已稳定可用，移动端正在开发中。</strong> Android 和 iOS 版本已进入开发阶段，与桌面端共享核心逻辑，UI 针对触摸屏重新设计。</p><h3 id="q5-如何获取更新" tabindex="-1">Q5：如何获取更新？ <a class="header-anchor" href="#q5-如何获取更新" aria-label="Permalink to &quot;Q5：如何获取更新？&quot;">​</a></h3><p><strong>直接下载最新版本安装即可，配置和数据不会丢失。</strong> 关注 GitHub Releases 页面即可获取版本通知。推荐下载 <strong>Pre-release 预览版</strong>，更新更频繁，功能最新。</p><hr><blockquote><p><strong>下一步</strong>：如果你还没有安装，请先阅读 <a href="./installation">安装指南</a>。如果已经安装好了，直接跳到 <a href="./getting-started">快速开始</a>，5 分钟上手核心操作。</p></blockquote>`,81)])])}const c=e(o,[["render",n]]);export{b as __pageData,c as default};
